```javascript
import { withDb } from "./db.mjs";

export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const row = (await client.query("SELECT doc FROM accounts LIMIT 1")).rows[0];
    const doc = row.doc;

    const accountId = doc._id;
    const requestId = doc.request?.requestId || `req-${accountId}`;
    const nowDate = new Date(now);

    // Derive risk signals in display order
    const signals = [];

    // Regulatory hold: a regulatory flag with status "open"
    if ((doc.regulatoryFlags || []).some(f => f.status === "open")) {
      signals.push("Regulatory hold");
    }

    // Overdue invoice: unpaid invoice past due date AND amount >= $25,000
    if ((doc.invoices || []).some(inv =>
      inv.status !== "paid" &&
      new Date(inv.dueDate) < nowDate &&
      inv.amountCents >= 2500000
    )) {
      signals.push("Overdue invoice");
    }

    // Delayed shipment: no delivered date AND past SLA date
    if ((doc.shipments || []).some(s =>
      !s.deliveredDate && new Date(s.slaDate) < nowDate
    )) {
      signals.push("Delayed shipment");
    }

    // Escalated support: open case with severity high or critical
    if ((doc.supportCases || []).some(s =>
      s.status === "open" && (s.severity === "high" || s.severity === "critical")
    )) {
      signals.push("Escalated support");
    }

    // Usage decline: current <= prior * 0.7
    const usage = doc.usage;
    if (usage && usage.currentPeriodUnits <= usage.priorPeriodUnits * 0.7) {
      signals.push("Usage decline");
    }

    const qualifyingTiers = ["strategic", "enterprise"];
    const qualifies = qualifyingTiers.includes(doc.tier) && signals.length > 0;

    const status = qualifies
      ? "At-risk escalation active with executive recovery owner routing and customer-visible audit history."
      : "Monitoring — no escalation required.";

    // Owner routing in fixed order, deduped
    const signalToOwner = {
      "Regulatory hold": "Legal",
      "Overdue invoice": "Finance",
      "Delayed shipment": "Customer Success",
      "Escalated support": "Support",
      "Usage decline": "Customer Success",
    };
    const ownerOrder = ["Legal", "Finance", "Customer Success", "Support"];
    const activeOwners = qualifies
      ? [...new Set(signals.map(s => signalToOwner[s]).filter(Boolean))]
          .sort((a, b) => ownerOrder.indexOf(a) - ownerOrder.indexOf(b))
      : [];

    const riskSummary = qualifies
      ? `${signals.length} signals: ${signals.join(", ")}`
      : "0 signals";

    const topOwner = activeOwners[0] || "";
    const nextStep = qualifies
      ? `${topOwner} recovery review by 16:00`
      : "Continue standard monitoring.";

    // Clear existing data
    await client.query("DELETE FROM workflow_state");
    await client.query("DELETE FROM owner_tasks");
    await client.query("DELETE FROM customer_messages");
    await client.query("DELETE FROM audit_events");

    // Persist workflow_state
    await client.query(
      `INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary)
       VALUES ($1, $2, $3, $4, $5, $6)`,
      [requestId, accountId, "Strategic account rescue", status, nextStep, riskSummary]
    );

    // Persist owner_tasks (in fixed order)
    for (const owner of activeOwners) {
      await client.query(
        `INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status)
         VALUES ($1, $2, $3, $4, $5, $6)`,
        [requestId, accountId, owner, `${owner} recovery review`, nowDate.toISOString(), "open"]
      );
    }

    // Persist customer_messages (no internal ids/codes)
    const customerMessage = qualifies
      ? `Your account has been flagged for priority attention by our executive recovery team. We have identified ${signals.length} active risk area${signals.length !== 1 ? "s" : ""} that require immediate resolution. A dedicated recovery owner has been assigned and will be in touch shortly to coordinate next steps and ensure your service continuity is maintained.`
      : `Your account is currently being monitored under standard protocols. No escalation is required at this time. Our team will continue to track your account health and will reach out if any action becomes necessary.`;

    await client.query(
      `INSERT INTO customer_messages (request_id, account_id, body)
       VALUES ($1, $2, $3)`,
      [requestId, accountId, customerMessage]
    );

    // Persist audit_events (customer_visible = true)
    await client.query(
      `INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible)
       VALUES ($1, $2, $3, $4, $5)`,
      [requestId, accountId, `Rescue workflow initiated. ${status}`, nowDate.toISOString(), true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}
