+    const activeOwners = qualifies
+      ? (() => {
+          const owners = new Set();
+          for (const cat of Object.keys(fired)) owners.add(OWNER_FOR_CATEGORY[cat]);
+          return OWNER_ORDER.filter((o) => owners.has(o));
+        })()
+      : [];
+
+    const status = qualifies
+      ? "At-risk escalation active with executive recovery owner routing and customer-visible audit history."
+      : "Monitoring — no escalation required.";
+
+    const nextStep = qualifies
+      ? `${activeOwners[0]} recovery review by 16:00`
+      : "Continue standard monitoring.";
+
+    const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;
+
+    // Clear existing data
+    await client.query("DELETE FROM workflow_state");
+    await client.query("DELETE FROM owner_tasks");
+    await client.query("DELETE FROM customer_messages");
+    await client.query("DELETE FROM audit_events");
+
+    // Persist workflow_state
+    await client.query(
+      `INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary)
+       VALUES ($1, $2, $3, $4, $5, $6)`,
+      [requestId, accountId, "Strategic account rescue", status, nextStep, riskSummary]
+    );
+
+    // Persist owner_tasks in fixed order
+    for (const owner of activeOwners) {
+      await client.query(
+        `INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status)
+         VALUES ($1, $2, $3, $4, $5, $6)`,
+        [requestId, accountId, owner, `${owner} recovery review`, nowDate.toISOString(), "open"]
+      );
+    }
+
+    // Persist customer_messages (no internal ids/codes)
+    const customerMessage = qualifies
+      ? `Your account has been flagged for priority attention by our executive recovery team. We have identified ${signals.length} active risk area${signals.length !== 1 ? "s" : ""} that require immediate resolution. A dedicated recovery owner has been assigned and will be in touch shortly to coordinate next steps and ensure your service continuity is maintained.`
+      : `Your account is currently being monitored under standard protocols. No escalation is required at this time. Our team will continue to track your account health and will reach out if any action becomes necessary.`;
+
+    await client.query(
+      `INSERT INTO customer_messages (request_id, account_id, body)
+       VALUES ($1, $2, $3)`,
+      [requestId, accountId, customerMessage]
+    );
+
+    // Persist audit_events (customer_visible = true)
+    await client.query(
+      `INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible)
+       VALUES ($1, $2, $3, $4, $5)`,
+      [requestId, accountId, `Rescue workflow initiated. ${status}`, nowDate.toISOString(), true]
+    );
+  });
